class Solution:
    def matrixReshape(self, mat, r, c):
        m = len(mat)
        n = len(mat[0])
        if m * n != r * c:
            return mat
        flat = []
        for row in mat:
            for v in row:
                flat.append(v)
        res = []
        idx = 0
        for _ in range(r):
            row = []
            for _ in range(c):
                row.append(flat[idx])
                idx += 1
            res.append(row)
        return res

