var matrixReshape = function(mat, r, c) {
    const m = mat.length, n = mat[0].length;
    if (m * n !== r * c) return mat;
    const res = Array.from({ length: r }, () => new Array(c).fill(0));
    for (let k = 0; k < m * n; k++) {
        res[Math.floor(k / c)][k % c] = mat[Math.floor(k / n)][k % n];
    }
    return res;
};
